def edit_distance(word1, word2):
    m, n = len(word1), len(word2)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m+1): dp[i][0]=i
    for j in range(n+1): dp[0][j]=j
    for i in range(1, m+1):
        for j in range(1, n+1):
            if word1[i-1]==word2[j-1]:
                dp[i][j]=dp[i-1][j-1]
            else:
                dp[i][j]=min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1])+1
    return dp[m][n]

def max_subarray_sum(nums):
    max_ending = max_so_far = nums[0]
    for x in nums[1:]:
        max_ending = max(x, max_ending+x)
        max_so_far = max(max_so_far, max_ending)
    return max_so_far

def is_valid_bst(root, min_val=float('-inf'), max_val=float('inf')):
    if not root: return True
    if root.val <= min_val or root.val >= max_val: return False
    return is_valid_bst(root.left, min_val, root.val) and is_valid_bst(root.right, root.val, max_val)

def path_sum(root, target):
    def dfs(node, curr):
        if not node: return 0
        curr += node.val
        return (1 if curr==target else 0) + dfs(node.left, curr) + dfs(node.right, curr)
    if not root: return 0
    return dfs(root,0) + path_sum(root.left,target) + path_sum(root.right,target)

def group_anagrams(strs):
    from collections import defaultdict
    d = defaultdict(list)
    for s in strs:
        key = ''.join(sorted(s))
        d[key].append(s)
    return list(d.values())
